ALGORITHM DKIM_Sign
INPUT: email_message, private_key, selector, domain
OUTPUT: dkim_header

BEGIN
 // Step 1: Canonicalize the header (normalize for signing)
 canonical_header = CanonicalizeHeader(email_message.headers)

 // Step 2: Create the DKIM-Signature header template
 signature_header = CreateSignatureHeader(domain, selector, "rsa-sha256")

 // Step 3: Compute SHA-256 hash of canonicalized header
 header_hash = SHA256(canonical_header)

 // Step 4: Sign the hash using RSA private key
 signature = RSASign(header_hash, private_key)

 // Step 5: Base64 encode the signature
 encoded_signature = Base64Encode(signature)

 // Step 6: Construct the full DKIM-Signature header
 dkim_header = BuildDKIMHeader(signature_header, encoded_signature)

 RETURN dkim_header
END

ALGORITHM DKIM_Verify
INPUT: email_message, dkim_header, public_key_dns
OUTPUT: verification_result (TRUE/FALSE)

BEGIN
 // Step 1: Extract signature and selector from DKIM header
 signature = ExtractSignature(dkim_header)
 selector = ExtractSelector(dkim_header)
 domain = ExtractDomain(dkim_header)

 // Step 2: Fetch public key from DNS using selector
 public_key = DNSLookup(selector + "._domainkey." + domain)

 // Step 3: Decode the Base64 signature
 decoded_signature = Base64Decode(signature)

 // Step 4: Canonicalize the header (same as signing)
 canonical_header = CanonicalizeHeader(email_message.headers)

 // Step 5: Compute SHA-256 hash of canonicalized header
 header_hash = SHA256(canonical_header)

 // Step 6: Verify signature using RSA public key
 decrypted_hash = RSAVerify(decoded_signature, public_key)

 // Step 7: Compare hashes
 IF header_hash == decrypted_hash THEN
 RETURN TRUE // Signature is valid
 ELSE
 RETURN FALSE // Signature is invalid
 ENDIF
END

/*
 * DKIM Cryptographic Operations in C
 * Uses OpenSSL for RSA and SHA-256 operations
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <openssl/rsa.h>
#include <openssl/sha.h>
#include <openssl/pem.h>
#include <openssl/err.h>

#define KEY_SIZE 2048
#define MAX_HEADER_LEN 1024

/* Structure to hold DKIM key pair */
typedef struct {
 RSA *public_key;
 RSA *private_key;
} DKIMKeyPair;

/* Generate RSA key pair for DKIM */
DKIMKeyPair* generate_keypair(int key_size) {
 DKIMKeyPair *keys = malloc(sizeof(DKIMKeyPair));
 if (!keys) return NULL;

 RSA *rsa = RSA_generate_key(key_size, RSA_F4, NULL, NULL);
 if (!rsa) {
 free(keys);
 return NULL;
 }

 keys->public_key = rsa;
 keys->private_key = rsa;

 return keys;
}

/* Canonicalize email header per DKIM specification (simple) */
void canonicalize_header(const char *header_name, const char *header_value, 
 char *output) {
 /* Simple canonicalization: lowercase header name, preserve value */
 int i = 0;
 while (*header_name) {
 output[i++] = tolower(*header_name++);
 }
 output[i++] = ':';
 strcpy(output + i, header_value);
}

/* Compute SHA-256 hash of data */
int compute_sha256(const unsigned char *data, size_t len, unsigned char *hash) {
 return SHA256(data, len, hash);
}

/* Sign data using RSA private key (DKIM signature generation) */
int dkim_sign(const unsigned char *message, size_t msg_len,
 RSA *private_key, unsigned char **signature, size_t *sig_len) {
 unsigned char hash[SHA256_DIGEST_LENGTH];
 unsigned char *encrypted = NULL;

 /* Step 1: Compute SHA-256 hash of message */
 compute_sha256(message, msg_len, hash);

 /* Step 2: Determine RSA key length */
 int key_len = RSA_size(private_key);
 encrypted = malloc(key_len);
 if (!encrypted) return 0;

 /* Step 3: Sign the hash with RSA private key */
 int result = RSA_sign(NID_sha256, hash, SHA256_DIGEST_LENGTH,
 encrypted, (unsigned int*)sig_len, private_key);

 if (result) {
 *signature = encrypted;
 } else {
 free(encrypted);
 }

 return result;
}

/* Verify RSA signature (DKIM verification) */
int dkim_verify(const unsigned char *message, size_t msg_len,
 const unsigned char *signature, size_t sig_len,
 RSA *public_key) {
 unsigned char hash[SHA256_DIGEST_LENGTH];

 /* Step 1: Compute SHA-256 hash of message */
 compute_sha256(message, msg_len, hash);

 /* Step 2: Verify signature using public key */
 return RSA_verify(NID_sha256, hash, SHA256_DIGEST_LENGTH,
 signature, sig_len, public_key);
}

/* Base64 encode function */
char* base64_encode(const unsigned char *data, size_t len) {
 static const char b64_table[] = 
 "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";

 char *result = malloc(((len + 2) / 3) * 4 + 1);
 int i, j = 0;

 for (i = 0; i < len; i += 3) {
 int a = data[i];
 int b = (i + 1 < len) ? data[i + 1] : 0;
 int c = (i + 2 < len) ? data[i + 2] : 0;

 result[j++] = b64_table[a >> 2];
 result[j++] = b64_table[((a & 0x03) << 4) | (b >> 4)];
 result[j++] = (i + 1 < len) ? b64_table[((b & 0x0F) << 2) | (c >> 6)] : '=';
 result[j++] = (i + 2 < len) ? b64_table[c & 0x3F] : '=';
 }
 result[j] = '\0';

 return result;
}

/* Build DKIM-Signature header */
void build_dkim_header(const char *domain, const char *selector,
 const char *encoded_signature, char *output) {
 sprintf(output, 
 "DKIM-Signature: v=1; a=rsa-sha256; c=simple; d=%s; s=%s; "
 "h=from:to:subject; bh=; b=%s",
 domain, selector, encoded_signature);
}

/* Simulate DNS TXT record lookup for DKIM public key */
void get_public_key_dns(const char *selector, const char *domain, char *output) {
 /* In real implementation, this would query DNS
 * For simulation, we output the lookup format */
 sprintf(output, "v=DKIM1; k=rsa; p=<public_key_for_%s.%s>", selector, domain);
}

int main() {
 printf("=== DKIM Cryptographic Operations Demo ===\n\n");

 /* Initialize OpenSSL */
 OpenSSL_add_all_algorithms();
 ERR_load_crypto_strings();

 /* Generate DKIM key pair */
 printf("1. Generating RSA key pair (2048 bits)...\n");
 DKIMKeyPair *keys = generate_keypair(KEY_SIZE);
 if (!keys) {
 printf("Error generating keys\n");
 return 1;
 }
 printf(" Keys generated successfully!\n");

 /* Create sample email headers to sign */
 const char *from_header = "From: sender@example.com";
 const char *to_header = "To: recipient@example.com";
 const char *subject_header = "Subject: DKIM Test";

 char canonicalized[MAX_HEADER_LEN * 3];
 sprintf(canonicalized, "%s\n%s\n%s", 
 from_header, to_header, subject_header);

 printf("\n2. Canonicalized headers:\n%s\n", canonicalized);

 /* Sign the headers */
 printf("3. Signing headers with RSA private key...\n");
 unsigned char *signature = NULL;
 size_t sig_len = 0;

 if (dkim_sign((unsigned char*)canonicalized, strlen(canonicalized),
 keys->private_key, &signature, &sig_len)) {
 char *b64_sig = base64_encode(signature, sig_len);
 printf(" Signature (Base64): %.64s...\n", b64_sig);

 /* Build DKIM header */
 char dkim_header[1024];
 build_dkim_header("example.com", "mail", b64_sig, dkim_header);
 printf("\n4. DKIM-Signature header:\n%s\n", dkim_header);

 /* Verify the signature */
 printf("\n5. Verifying signature with public key...\n");
 if (dkim_verify((unsigned char*)canonicalized, strlen(canonicalized),
 signature, sig_len, keys->public_key)) {
 printf(" ✓ Signature VERIFIED successfully!\n");
 } else {
 printf(" ✗ Verification FAILED!\n");
 }

 /* Simulate tampering detection */
 printf("\n6. Testing tamper detection...\n");
 const char *tampered = "From: sender@example.com\nTo: recipient@example.com\nSubject: HACKED";

 if (dkim_verify((unsigned char*)tampered, strlen(tampered),
 signature, sig_len, keys->public_key)) {
 printf(" ✗ Tampered message PASSED (should fail!)\n");
 } else {
 printf(" ✓ Tampered message FAILED verification (correct!)\n");
 }

 free(b64_sig);
 }

 /* Cleanup */
 RSA_free(keys->public_key);
 free(keys);
 EVP_cleanup();

 printf("\n=== Demo Complete ===\n");
 return 0;
}
